     {q:"The success rate of IVF ___.", options:["is higher for older patients","is 100% for all patients","decreases significantly with maternal age","is unaffected by age"], answer:2},
     {q:"Surrogacy raises ethical questions including ___.", options:["only concerns for surrogate health","no ethical concerns exist","only legal questions about parentage","exploitation of economically vulnerable women, commodification of reproduction, questions of consent and autonomy, and child welfare regarding knowledge of origins"], answer:3},
     {q:"Reproductive technologies disproportionately raise questions of ___.", options:["only medical safety","only scientific feasibility","no access concerns","equitable access"], answer:3}
